268→#[derive(Debug, Clone)]
269→pub struct jjrm_McpServer {
270→    tool_router: ToolRouter<Self>,
271→}
272→
273→#[tool_router]
274→impl jjrm_McpServer {
275→    pub fn jjrm_new() -> Self {
276→        Self {
277→            tool_router: Self::tool_router(),
278→        }
279→    }
280→
281→    #[tool(name = "jjx", description = "Job Jockey Kit - MCP tools for project initiative management")]
282→    async fn jjx(&self, Parameters(p): Parameters<jjrm_JjxParams>) -> Result<CallToolResult, McpError> {
283→        let cmd = p.command.as_str();
284→        let v = p.params;
285→
286→        macro_rules! deser {
287→            ($t:ty) => {
288→                match serde_json::from_value::<$t>(v) {
289→                    Ok(p) => p,
290→                    Err(e) => return jjrm_deser_error(cmd, e),
291→                }
292→            }
293→        }
294→
295→        match cmd {
296→            "jjx_record" => {
297→                let p = deser!(jjrm_RecordParams);
298→                jjrm_result(jjrnc_run_notch(jjrnc_NotchArgs {
299→                    identity: p.identity,
300→                    files: p.files,
301→                    size_limit: p.size_limit,
302→                    intent: p.intent,
303→                }))
304→            }
305→            "jjx_mark" => {
306→                let p = deser!(jjrm_MarkParams);
307→                jjrm_result(jjrx_run_chalk(jjrx_ChalkArgs {
308→                    identity: p.identity,
309→                    marker: p.marker,
310→                    description: p.description,
311→                }))
312→            }
313→            "jjx_log" => {
314→                let p = deser!(jjrm_LogParams);
315→                jjrm_result(jjrrn_run_rein(jjrrn_ReinArgs {
316→                    firemark: p.firemark,
317→                    limit: p.limit.unwrap_or(50),
318→                }))
319→            }
320→            "jjx_validate" => {
321→                let _p = deser!(jjrm_ValidateParams);
322→                jjrm_result(jjrvl_run_validate(jjrvl_ValidateArgs {
323→                    file: gallops_pathbuf(),
324→                }))
325→            }
326→            "jjx_list" => {
327→                let p = deser!(jjrm_ListParams);
328→                jjrm_result(jjrmu_run_muster(jjrmu_MusterArgs {
329→                    file: gallops_pathbuf(),
330→                    status: p.status,
331→                }).await)
332→            }
333→            "jjx_orient" => {
334→                let p = deser!(jjrm_OrientParams);
335→                jjrm_result(jjrsd_run_saddle(jjrsd_SaddleArgs {
336→                    file: gallops_pathbuf(),
337→                    firemark: p.firemark,
338→                }).await)
339→            }
340→            "jjx_show" => {
341→                let p = deser!(jjrm_ShowParams);
342→                jjrm_result(jjrpd_run_parade(jjrpd_ParadeArgs {
343→                    file: gallops_pathbuf(),
344→                    target: p.target,
345→                    detail: p.detail,
346→                    remaining: p.remaining,
347→                }))
348→            }
349→            "jjx_archive" => {
350→                let p = deser!(jjrm_ArchiveParams);
351→                jjrm_result(jjrrt_run_retire(jjrrt_RetireArgs {
352→                    file: gallops_pathbuf(),
353→                    firemark: p.firemark,
354→                    size_limit: p.size_limit,
355→                }))
356→            }
357→            "jjx_create" => {
358→                let p = deser!(jjrm_CreateParams);
359→                jjrm_result(jjrx_run_nominate(jjrx_NominateArgs {
360→                    file: gallops_pathbuf(),
361→                    silks: p.silks,
362→                }))
363→            }
364→            "jjx_enroll" => {
365→                let p = deser!(jjrm_EnrollParams);
366→                jjrm_result(jjrsl_run_slate(jjrsl_SlateArgs {
367→                    file: gallops_pathbuf(),
368→                    firemark: p.firemark,
369→                    silks: p.silks,
370→                    before: p.before,
371→                    after: p.after,
372→                    first: p.first,
373→                }, p.docket))
374→            }
375→            "jjx_reorder" => {
376→                let p = deser!(jjrm_ReorderParams);
377→                jjrm_result(jjrrl_run_rail(jjrrl_RailArgs {
378→                    file: gallops_pathbuf(),
379→                    firemark: p.firemark,
380→                    order: vec![],
381→                    r#move: p.r#move,
382→                    before: p.before,
383→                    after: p.after,
384→                    first: p.first,
385→                    last: p.last,
386→                }))
387→            }
388→            "jjx_revise_docket" => {
389→                let p = deser!(jjrm_ReviseDocketParams);
390→                jjrm_result(jjrtl_run_revise_docket(jjrtl_ReviseDocketArgs {
391→                    file: gallops_pathbuf(),
392→                    coronet: p.coronet,
393→                }, p.docket))
394→            }
395→            "jjx_arm" => {
396→                let p = deser!(jjrm_ArmParams);
397→                jjrm_result(jjrtl_run_arm(jjrtl_ArmArgs {
398→                    file: gallops_pathbuf(),
399→                    coronet: p.coronet,
400→                }, p.warrant))
401→            }
402→            "jjx_relabel" => {
403→                let p = deser!(jjrm_RelabelParams);
404→                jjrm_result(jjrtl_run_relabel(jjrtl_RelabelArgs {
405→                    file: gallops_pathbuf(),
406→                    coronet: p.coronet,
407→                    silks: p.silks,
408→                }))
409→            }
410→            "jjx_drop" => {
411→                let p = deser!(jjrm_DropParams);
412→                jjrm_result(jjrtl_run_drop(jjrtl_DropArgs {
413→                    file: gallops_pathbuf(),
414→                    coronet: p.coronet,
415→                }))
416→            }
417→            "jjx_relocate" => {
418→                let p = deser!(jjrm_RelocateParams);
419→                jjrm_result(jjrdr_run_draft(jjrdr_DraftArgs {
420→                    file: gallops_pathbuf(),
421→                    coronet: p.coronet,
422→                    to: p.to,
423→                    before: p.before,
424→                    after: p.after,
425→                    first: p.first,
426→                }))
427→            }
428→            "jjx_alter" => {
429→                let p = deser!(jjrm_AlterParams);
430→                jjrm_result(jjrfu_run_furlough(jjrfu_FurloughArgs {
431→                    file: gallops_pathbuf(),
432→                    firemark: p.firemark,
433→                    racing: p.racing,
434→                    stabled: p.stabled,
435→                    silks: p.silks,
436→                }))
437→            }
438→            "jjx_close" => {
439→                let p = deser!(jjrm_CloseParams);
440→                jjrm_result(zjjrx_run_wrap(jjrx_WrapArgs {
441→                    coronet: p.coronet,
442→                    size_limit: p.size_limit,
443→                }, p.summary))
444→            }
445→            "jjx_search" => {
446→                let p = deser!(jjrm_SearchParams);
447→                jjrm_result(jjrsc_run_scout(jjrsc_ScoutArgs {
448→                    file: gallops_pathbuf(),
449→                    pattern: p.pattern,
450→                    actionable: p.actionable,
451→                }))
452→            }
453→            "jjx_get_brief" => {
454→                let p = deser!(jjrm_GetBriefParams);
455→                jjrm_result(jjrgs_run_get_spec(jjrgs_GetSpecArgs {
456→                    file: gallops_pathbuf(),
457→                    coronet: p.coronet,
458→                }))
459→            }
460→            "jjx_get_coronets" => {
461→                let p = deser!(jjrm_GetCoronetsParams);
462→                jjrm_result(jjrgc_run_get_coronets(jjrgc_GetCoronetsArgs {
463→                    file: gallops_pathbuf(),
464→                    firemark: p.firemark,
465→                    remaining: p.remaining,
466→                    rough: p.rough,
467→                }))
468→            }
469→            "jjx_paddock" => {
470→                let p = deser!(jjrm_PaddockParams);
471→                jjrm_result(jjrcu_run_curry(jjrcu_CurryArgs {
472→                    file: gallops_pathbuf(),
473→                    firemark: p.firemark,
474→                    note: p.note,
475→                }, p.content))
476→            }
477→            "jjx_continue" => {
478→                let p = deser!(jjrm_ContinueParams);
479→                jjrm_result(jjrgl_run_garland(jjrgl_GarlandArgs {
480→                    file: gallops_pathbuf(),
481→                    firemark: p.firemark,
482→                }))
483→            }
484→            "jjx_transfer" => {
485→                let p = deser!(jjrm_TransferParams);
486→                jjrm_result(jjrrs_run(jjrrs_RestringArgs {
487→                    file: gallops_pathbuf(),
488→                    firemark: p.firemark,
489→                    to: p.to,
490→                }, p.coronets))
491→            }
492→            "jjx_landing" => {
493→                let p = deser!(jjrm_LandingParams);
494→                jjrm_result(jjrld_run_landing(jjrld_LandingArgs {
495→                    coronet: p.coronet,
496→                    agent: p.agent,
497→                }, p.content.unwrap_or_default()))
498→            }
499→            _ => {
500→                Ok(CallToolResult::error(vec![Content::text(format!("jjx: unknown command '{}'\nAvailable: jjx_list, jjx_show, jjx_orient, jjx_record, jjx_mark, jjx_log, jjx_validate, jjx_create, jjx_enroll, jjx_close, jjx_archive, jjx_reorder, jjx_revise_docket, jjx_arm, jjx_relabel, jjx_drop, jjx_relocate, jjx_alter, jjx_search, jjx_get_brief, jjx_get_coronets, jjx_paddock, jjx_continue, jjx_transfer, jjx_landing", cmd))]))
501→            }
502→        }
503→    }
504→}
