521→/// Start MCP stdio server. Blocks until client disconnects.
522→pub async fn jjrm_serve_stdio() -> Result<(), Box<dyn std::error::Error>> {
523→    use rmcp::ServiceExt;
524→
525→    let server = jjrm_McpServer::jjrm_new();
526→    let service = server
527→        .serve(rmcp::transport::stdio())
528→        .await
529→        .map_err(|e| format!("MCP serve error: {}", e))?;
530→
531→    service.waiting().await?;
532→    Ok(())
533→}
